#include <vector>

class MKAverage {
public:
    MKAverage(int m, int k) {
        nums = std::vector<int>(m);
        for (int i = 0; i < m; i++) {
            nums[i] = input[i];
        }
    }

    void addElement(int num) {
        nums.push_back(num);
    }

    int calculateMKAverage() {
        int sum = 0;
        for (int i = m - 1; i >= 0; i--) {
            sum += nums[i];
        }
        int count = nums.size();
        int result = sum / count;
        return result;
    }
};
